function validateIndex(index) {
  const indices = index.split(',').map(s => s.trim());
  for (const idx of indices) {
    // Check against whitelist - support wildcard patterns
    let matched = false;
    for (const allowed of ALLOWED_INDICES) {
      if (idx === allowed || (allowed.endsWith('*') && idx.startsWith(allowed.slice(0, -1)))) {
        matched = true;
        break;
      }
    }
    if (!matched) {
      throw new Error(`Index "${idx}" is not in the allowed indices list`);
    }
  }
  return index;
}

function buildFilter(filter) {
  const field = sanitizeFieldName(filter.field);

  switch (filter.type) {
    case 'term':
      return { term: { [field]: sanitizeValue(filter.value) } };
    case 'terms':
      if (!Array.isArray(filter.value)) {
        throw new Error('terms filter requires an array value');
      }
      return { terms: { [field]: filter.value.map(sanitizeValue) } };
    case 'range': {
      const rangeObj = {};
      if (filter.gte !== undefined) rangeObj.gte = filter.gte;
      if (filter.lte !== undefined) rangeObj.lte = filter.lte;
      if (filter.gt !== undefined) rangeObj.gt = filter.gt;
      if (filter.lt !== undefined) rangeObj.lt = filter.lt;
      return { range: { [field]: rangeObj } };
    }
    case 'exists':
      return { exists: { field: field } };
    default:
      throw new Error(`Unsupported filter type: ${filter.type}`);
  }
}

function buildQuery(params) {
  const query = {};

  // Build the base query
  let baseQuery;
  if (params.query_text && params.query_text.trim()) {
    const fields = params.query_fields || ['_all'];
    fields.forEach(sanitizeFieldName);

    baseQuery = {
      multi_match: {
        query: params.query_text.trim(),
        fields: fields,
        type: 'best_fields',
        fuzziness: 'AUTO',
      },
    };
  } else {
    baseQuery = { match_all: {} };
  }

  // Build filters
  let filterClauses = [];
  if (params.filters && params.filters.length > 0) {
    filterClauses = params.filters.map(buildFilter);
  }

  // Combine base query with filters
  let combinedQuery;
  if (filterClauses.length > 0) {
    combinedQuery = {
      bool: {
        must: [baseQuery],
        filter: filterClauses,
      },
    };
  } else {
    combinedQuery = baseQuery;
  }

  // Apply scoring functions if provided
  if (params.scoring_functions && params.scoring_functions.length > 0) {
    const functions = [];
    let hasScriptScore = false;

    for (const sf of params.scoring_functions) {
      const funcDef = ALLOWED_SCORING_FUNCTIONS[sf.function_name];
      if (!funcDef) {
        throw new Error(`Unknown scoring function: ${sf.function_name}`);
      }

      const builtFunc = funcDef.build(sf.params);

      // script_score functions need special handling
      if (builtFunc.script_score) {
        hasScriptScore = true;
        functions.push(builtFunc);
      } else {
        functions.push(builtFunc);
      }
    }

    query.query = {
      function_score: {
        query: combinedQuery,
        functions: functions,
        score_mode: params.score_mode || 'sum',
        boost_mode: params.boost_mode || 'multiply',
      },
    };

    if (params.min_score !== undefined) {
      query.query.function_score.min_score = params.min_score;
    }
  } else {
    query.query = combinedQuery;
  }

  // Pagination
  query.from = params.from || 0;
  query.size = params.size || 10;

  // Sorting
  if (params.sort && params.sort.length > 0) {
    query.sort = params.sort;
  }

  // Highlighting
  if (params.highlight) {
    query.highlight = {
      fields: {},
    };
    for (const [field, config] of Object.entries(params.highlight.fields)) {
      sanitizeFieldName(field);
      query.highlight.fields[field] = config || {};
    }
    if (params.highlight.pre_tags) {
      query.highlight.pre_tags = params.highlight.pre_tags;
    }
    if (params.highlight.post_tags) {
      query.highlight.post_tags = params.highlight.post_tags;
    }
  }

  // Aggregations
  if (params.aggregations) {
    query.aggs = {};
    for (const [name, aggConfig] of Object.entries(params.aggregations)) {
      const field = sanitizeFieldName(aggConfig.field);
      switch (aggConfig.type) {
        case 'terms':
          query.aggs[name] = { terms: { field, size: aggConfig.size || 10 } };
          break;
        case 'histogram':
          query.aggs[name] = { histogram: { field, interval: aggConfig.interval || 10 } };
          break;
        case 'date_histogram':
          query.aggs[name] = {
            date_histogram: {
              field,
              calendar_interval: aggConfig.calendar_interval || 'month',
            },
          };
          break;
        case 'avg':
        case 'sum':
        case 'min':
        case 'max':
        case 'cardinality':
        case 'stats':
          query.aggs[name] = { [aggConfig.type]: { field } };
          break;
        default:
          throw new Error(`Unsupported aggregation type: ${aggConfig.type}`);
      }
    }
  }

  // Source filtering
  if (params.source_includes || params.source_excludes) {
    query._source = {};
    if (params.source_includes) {
      query._source.includes = params.source_includes.map(sanitizeFieldName);
    }
    if (params.source_excludes) {
      query._source.excludes = params.source_excludes.map(sanitizeFieldName);
    }
  }

  return query;
}

