app.post('/api/search', async (req, res) => {
  try {
    // Validate input
    const { error, value: params } = searchSchema.validate(req.body, {
      abortEarly: false,
      stripUnknown: true,
    });

    if (error) {
      return res.status(400).json({
        error: 'Validation error',
        details: error.details.map(d => d.message),
      });
    }

    // Validate index against whitelist
    try {
      validateIndex(params.index);
    } catch (indexError) {
      return res.status(403).json({
        error: 'Forbidden',
        message: indexError.message,
      });
    }

    // Build the query
    const queryBody = buildQuery(params);

    console.log('Executing query:', JSON.stringify({
      index: params.index,
      query_structure: Object.keys(queryBody),
      timestamp: new Date().toISOString(),
    }));

    // Execute the search
    const result = await esClient.search({
      index: params.index,
      body: queryBody,
    });

    // Format response
    const response = {
      total: typeof result.hits.total === 'object' ? result.hits.total.value : result.hits.total,
      max_score: result.hits.max_score,
      took: result.took,
      hits: result.hits.hits.map(hit => ({
        id: hit._id,
        index: hit._index,
        score: hit._score,
        source: hit._source,
        highlight: hit.highlight || undefined,
      })),
    };

    if (result.aggregations) {
      response.aggregations = result.aggregations;
    }

    res.json(response);
  } catch (err) {
    console.error('Search error:', {
      message: err.message,
      timestamp: new Date().toISOString(),
    });

    if (err.meta && err.meta.statusCode) {
      return res.status(err.meta.statusCode).json({
        error: 'Elasticsearch error',
        message: err.message,
      });
    }

    res.status(500).json({
      error: 'Internal server error',
      message: err.message,
    });
  }
});

// Explain endpoint - shows how a document was scored
app.post('/api/explain', async (req, res) => {
  try {
    const explainSchema = searchSchema.keys({
      document_id: Joi.string().pattern(/^[a-zA-Z0-9_\-]{1,512}$/).required(),
    });

    const { error, value: params } = explainSchema.validate(req.body, {
      abortEarly: false,
      stripUnknown: true,
    });

    if (error) {
      return res.status(400).json({
        error: 'Validation error',
        details: error.details.map(d => d.message),
      });
    }

    try {
      validateIndex(params.index);
    } catch (indexError) {
      return res.status(403).json({
        error: 'Forbidden',
        message: indexError.message,
      });
    }

    const queryBody = buildQuery(params);

    const result = await esClient.explain({
      index: params.index,
      id: params.document_id,
      body: { query: queryBody.query },
    });

    res.json({
      matched: result.matched,
      explanation: result.explanation,
    });
  } catch (err) {
    console.error('Explain error:', {
      message: err.message,
      timestamp: new Date().toISOString(),
    });

    if (err.meta && err.meta.statusCode === 404) {
      return res.status(404).json({
        error: 'Document not found',
      });
    }

    res.status(500).json({
      error: 'Internal server error',
      message: err.message,
    });
  }
});

